#!/usr/bin/env python3
"""
solution.py

Reads 'numbers.txt', sums all integers (one per line),
and prints the total.
"""

def main():
    total = 0
    try:
        with open("numbers.txt", "r") as f:
            for line in f:
                stripped = line.strip()
                if stripped:  # skip empty lines
                    try:
                        num = int(stripped)
                        total += num
                    except ValueError:
                        # ignore non-integer lines or report error
                        print(f"Warning: Skipping invalid integer '{stripped}'")
    except FileNotFoundError:
        print("Error: 'numbers.txt' not found.")
        return

    print(total)

if __name__ == "__main__":
    main()
